import {useState} from 'react';

const App = () => {
 const [inpText, setInpText] = useState('default')
 return (
  &lt;>
   &lt;div className="bg-taupe-100">
    &lt;input
     className="text-slate-800 hover:text-indigo-600 focus:text-red-700"
     onChange={(e) => setInpText(e.target.value)}
     value={inpText}
    />
   &lt;/div>
  &lt;/>
 )
}

export default App
